    override fun lift(value: Long): Server {
        return Server(UniffiWithHandle, value)
    }

    override fun read(buf: ByteBuffer): Server {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: Server) = 8UL

    override fun write(value: Server, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}



